args.sparql:
SELECT ?team ?teamLabel WHERE {
  ?player wdt:P1108 wd:Q193660;  # Fullback position
          wdt:P1035 ?college;
          wdt:P3391 ?draft.
  ?college wdt:P167 wd:Q12635.  # Big Ten Conference college
  ?draft wdt:P585 ?draftDate;
         p:P3391 ?draftStatement.
  ?draftStatement pq:P252 "7";  # 7th round
                 ps:P3391 ?player;
                 pr:P792 ?team.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
  FILTER (YEAR(?draftDate) = 1952)
}

SELECT DISTINCT ?draftTeam ?draftTeamLabel WHERE {
  ?player wdt:P1108 wd:Q285108;
